export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

const MAIN_ITEMS: Record<string, { insurance: number; base: number }> = {
  sword: { insurance: 1000, base: 100 },
  amulet: { insurance: 600, base: 60 },
  staff: { insurance: 800, base: 80 },
  potion: { insurance: 400, base: 40 },
};

const COMPONENT_INSURANCE = 250;
const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60; // for a block of 3 alike
const PROCESSING_FEE = 5;

export function isComponent(type: string): boolean {
  return !(type in MAIN_ITEMS);
}

export function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) {
    return MAIN_ITEMS[item.type].insurance;
  }
  return COMPONENT_INSURANCE;
}

export function policyInsuranceSum(items: Item[]): number {
  return items.reduce((sum, it) => sum + itemInsuranceValue(it), 0);
}

/**
 * Compute the item-level base premium, before customer-level modifiers.
 * Item modifiers (cursed, high enchantment) apply per item.
 * Component blocks of 3 alike use the special base premium of 60 G instead of 75 G.
 */
function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEMS) {
    return MAIN_ITEMS[item.type].base;
  }
  return COMPONENT_BASE;
}

function applyItemSurcharges(base: number, item: Item): number {
  let factor = 1;
  if (item.cursed) factor += 0.5;
  if ((item.enchantment ?? 0) >= 5) factor += 0.3;
  return base * factor;
}

/**
 * Group components into blocks of 3 alike, and return the
 * adjusted total base premium contribution including item-level
 * surcharges. Cursed/enchanted surcharges apply per item.
 */
function componentsPremium(components: Item[]): number {
  // group by type
  const byType: Record<string, Item[]> = {};
  for (const c of components) {
    (byType[c.type] ||= []).push(c);
  }
  let total = 0;
  for (const type of Object.keys(byType)) {
    const list = byType[type];
    // form blocks of 3
    const blocks = Math.floor(list.length / 3);
    const leftover = list.length % 3;
    let idx = 0;
    for (let b = 0; b < blocks; b++) {
      // The block of 3 has a base premium of 60 G total, but item-level
      // surcharges still apply per item. Distribute the block base across
      // the 3 items evenly (20 G each) so item-specific surcharges apply.
      const perItemBase = COMPONENT_BLOCK_BASE / 3;
      for (let j = 0; j < 3; j++) {
        total += applyItemSurcharges(perItemBase, list[idx]);
        idx++;
      }
    }
    for (let l = 0; l < leftover; l++) {
      total += applyItemSurcharges(COMPONENT_BASE, list[idx]);
      idx++;
    }
  }
  return total;
}

/**
 * Compute the premium for a list of items, given the customer and
 * the index of this contract (0 = first contract).
 */
export function computePremium(
  items: Item[],
  customer: Customer,
  contractIndex: number,
): number {
  // Separate main items vs components
  const mains: Item[] = [];
  const comps: Item[] = [];
  for (const it of items) {
    if (it.type in MAIN_ITEMS) mains.push(it);
    else comps.push(it);
  }

  let total = 0;
  for (const m of mains) {
    total += applyItemSurcharges(itemBasePremium(m), m);
  }
  total += componentsPremium(comps);

  // Customer-level modifiers
  let factor = 1;
  if (customer.yearsWithMHPCO >= 2) factor -= 0.2; // loyalty discount
  if (contractIndex === 0) {
    factor += 0.1; // first insurance: initial assessment surcharge
  } else {
    factor -= 0.15; // discount on each contract after the first
  }

  total = total * factor;
  total += PROCESSING_FEE;

  // Round up (MHPCO's favor)
  return Math.ceil(total);
}

import type { Item } from "./pricing.js";

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

const DEDUCTIBLE = 100;

/**
 * Compute payout for an incident against a policy.
 * - Items with enchantment >= 8: 50% reimbursement
 * - Items made of dragon material: 100% reimbursement
 * - Other items: not reimbursed
 * - Deductible of 100 G per incident (applied after reimbursement reductions)
 * - Capped at twice insurance sum (cumulative across all incidents on the policy)
 *
 * Returns the actual payout and the remaining cap after this claim.
 */
export function processClaim(
  incident: Incident,
  policyItems: Item[],
  insuranceSum: number,
  alreadyPaid: number,
): { payout: number; remainingCap: number } {
  const totalCap = 2 * insuranceSum;
  const remainingBefore = Math.max(0, totalCap - alreadyPaid);

  // For each damage line, decide reimbursement rate based on the
  // first matching item in the policy of the given itemType.
  let reimbursable = 0;
  for (const dmg of incident.damages) {
    const item = policyItems.find((it) => it.type === dmg.itemType);
    if (!item) continue;
    const dragon = item.material?.toLowerCase() === "dragon";
    const highEnchant = (item.enchantment ?? 0) >= 8;
    let rate = 0;
    if (dragon) rate = 1;
    else if (highEnchant) rate = 0.5;
    else rate = 0;
    reimbursable += dmg.amount * rate;
  }

  // Apply deductible per incident
  let payout = reimbursable - DEDUCTIBLE;
  if (payout < 0) payout = 0;

  // Round in MHPCO's favor (round down for payouts)
  payout = Math.floor(payout);

  // Apply remaining cap
  if (payout > remainingBefore) payout = remainingBefore;

  return { payout, remainingCap: remainingBefore - payout };
}

import {
  computePremium,
  policyInsuranceSum,
  type Customer,
  type Item,
} from "./pricing.js";
import { processClaim, type Incident } from "./claims.js";

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}
export interface ClaimResult {
  payout: number;
  remainingCap: number;
}
export type StepResult = QuoteResult | ClaimResult;

interface PolicyState {
  items: Item[];
  insuranceSum: number;
  paidOut: number;
}

export function runScenario(scenario: Scenario): { results: StepResult[] } {
  const results: StepResult[] = [];
  const policies = new Map<number, PolicyState>();
  let contractCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      const premium = computePremium(step.items, scenario.customer, contractCount);
      const insuranceSum = policyInsuranceSum(step.items);
      policies.set(i, {
        items: step.items,
        insuranceSum,
        paidOut: 0,
      });
      contractCount++;
      results.push({ premium });
    } else if (step.op === "claim") {
      const policy = policies.get(step.policy);
      if (!policy) {
        results.push({ payout: 0, remainingCap: 0 });
        continue;
      }
      const { payout, remainingCap } = processClaim(
        step.incident,
        policy.items,
        policy.insuranceSum,
        policy.paidOut,
      );
      policy.paidOut += payout;
      results.push({ payout, remainingCap });
    }
  }

  return { results };
}

import { runScenario, type Scenario } from "./scenario.js";

async function readStdin(): Promise<string> {
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(typeof chunk === "string" ? Buffer.from(chunk) : chunk);
  }
  return Buffer.concat(chunks).toString("utf8");
}

async function main() {
  const raw = await readStdin();
  const scenario = JSON.parse(raw) as Scenario;
  const out = runScenario(scenario);
  process.stdout.write(JSON.stringify(out));
}

main().catch((err) => {
  process.stderr.write(String(err) + "\n");
  process.exit(1);
});

import { describe, it, expect } from "vitest";
import { runScenario } from "./scenario.js";
import { computePremium } from "./pricing.js";

describe("computePremium", () => {
  it("sword for first-time customer: 100 base * 1.1 first + 5 fee = 115", () => {
    const p = computePremium(
      [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
      { yearsWithMHPCO: 0 },
      0,
    );
    expect(p).toBe(115);
  });

  it("amulet for loyal customer (5y): 60 * 0.8 loyalty * 1.1 first + 5 = 57.8 ⇒ 58", () => {
    const p = computePremium(
      [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
      { yearsWithMHPCO: 5 },
      0,
    );
    // 60 * (1 - 0.2 + 0.1) = 60 * 0.9 = 54 + 5 = 59
    expect(p).toBe(59);
  });

  it("cursed staff first-time: 80 * 1.5 cursed = 120 * 1.1 first + 5 = 137", () => {
    const p = computePremium(
      [{ type: "staff", material: "oak", enchantment: 0, cursed: true }],
      { yearsWithMHPCO: 0 },
      0,
    );
    // 80 * 1.5 = 120; * 1.1 = 132; + 5 = 137
    expect(p).toBe(137);
  });

  it("highly enchanted potion first-time: 40 * 1.3 = 52; * 1.1 = 57.2; +5 = 62.2 ⇒ 63", () => {
    const p = computePremium(
      [{ type: "potion", material: "glass", enchantment: 7, cursed: false }],
      { yearsWithMHPCO: 0 },
      0,
    );
    expect(p).toBe(63);
  });

  it("3 runes block of 3: 60 base * 1.1 + 5 = 71", () => {
    const items = [
      { type: "rune" },
      { type: "rune" },
      { type: "rune" },
    ];
    const p = computePremium(items, { yearsWithMHPCO: 0 }, 0);
    // block base 60 * 1.1 = 66 + 5 = 71
    expect(p).toBe(71);
  });

  it("4 runes: block of 3 (60) + 1 single (25) = 85; * 1.1 + 5 = 98.5 ⇒ 99", () => {
    const items = [
      { type: "rune" },
      { type: "rune" },
      { type: "rune" },
      { type: "rune" },
    ];
    const p = computePremium(items, { yearsWithMHPCO: 0 }, 0);
    expect(p).toBe(99);
  });

  it("second contract gets 15% discount (no first surcharge)", () => {
    const p = computePremium(
      [{ type: "sword" }],
      { yearsWithMHPCO: 0 },
      1,
    );
    // 100 * 0.85 = 85 + 5 = 90
    expect(p).toBe(90);
  });
});

describe("scenario", () => {
  it("processes quote + claims with deductible and cap", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 5 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "amulet", material: "silver", enchantment: 8, cursed: false },
          ],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "fire",
            damages: [{ itemType: "amulet", amount: 200 }],
          },
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "spell mishap",
            damages: [{ itemType: "amulet", amount: 250 }],
          },
        },
      ],
    });
    // amulet insurance sum = 600 ; cap = 1200
    // damage 200, enchant 8 ⇒ 50% = 100 - 100 deductible = 0
    // damage 250, enchant 8 ⇒ 50% = 125 - 100 = 25
    expect(out.results[0]).toEqual({ premium: expect.any(Number) });
    expect(out.results[1]).toEqual({ payout: 0, remainingCap: 1200 });
    expect(out.results[2]).toEqual({ payout: 25, remainingCap: 1175 });
  });

  it("dragon material is fully reimbursed and cap limits payout", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "dragon", enchantment: 1 }],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "battle",
            damages: [{ itemType: "sword", amount: 5000 }],
          },
        },
      ],
    });
    // sword insurance 1000, cap 2000
    // dragon ⇒ full 5000 - 100 = 4900, capped at 2000
    expect(out.results[1]).toEqual({ payout: 2000, remainingCap: 0 });
  });

  it("non-enchanted, non-dragon item: no reimbursement", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3 }],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "rust",
            damages: [{ itemType: "sword", amount: 500 }],
          },
        },
      ],
    });
    expect(out.results[1]).toEqual({ payout: 0, remainingCap: 2000 });
  });
});

